def summarize_cricket_performance(name, runs, wickets):
    if not runs and not wickets:
        return f"No cricket performance data available for {name}."

    performance_summary = []

    if runs:
        if isinstance(runs, dict):
            innings_summary = []
            for innings, score in runs.items():
                innings_summary.append(f"{innings}: {score} runs")
            performance_summary.append("Batting: " + ", ".join(innings_summary))
        else:
            performance_summary.append(f"Runs: {runs}")

    if wickets:
        if isinstance(wickets, dict):
            innings_summary = []
            for innings, wicket_info in wickets.items():
                wicket_info_str = ", ".join(f"{key}: {value}" for key, value in wicket_info.items())
                innings_summary.append(f"{innings}: {wicket_info_str}")
            performance_summary.append("Bowling: " + ", ".join(innings_summary))
        else:
            performance_summary.append(f"Wickets: {wickets}")

    return f"{name}'s cricket performance: " + "; ".join(performance_summary) + "."

# Example usage:
name = "Delroy Bertram Taylor"
runs = {"First innings": 60, "Second innings": 20}
wickets = {
    "First innings": {"wicket": "Michael Atherton", "runs conceded": 65, "overs": 10},
    "Second innings": {"wicket": "Warren Hegg", "runs conceded": 35, "overs": 7}
}
print(summarize_cricket_performance(name, runs, wickets))

Output: Delroy Bertram Taylor's cricket performance: Batting: First innings: 60 runs, Second innings: 20 runs; Bowling: First innings: wicket: Michael Atherton, runs conceded: 65, overs: 10, Second innings: wicket: Warren Hegg, runs conceded: 35, overs: 7.
